import React, { useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const GoogleCallback: React.FC = () => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { register } = useAuth();

  useEffect(() => {
    const handleGoogleCallback = async () => {
      try {
        const code = searchParams.get('code');
        const error = searchParams.get('error');

        if (error) {
          console.error('Google OAuth error:', error);
          navigate('/login?error=google_auth_failed');
          return;
        }

        if (!code) {
          console.error('No authorization code received');
          navigate('/login?error=no_code_received');
          return;
        }

        // محاكاة بيانات Google (في الواقع يجب أن ترسل الكود للـ Backend)
        // الآن سنقوم بإنشاء مستخدم وهمي من Google
        const googleUserData = {
          email: 'googleuser@gmail.com',
          firstName: 'Google',
          lastName: 'User',
        };

        // تسجيل المستخدم الجديد أو تسجيل الدخول
        await register(googleUserData);
        navigate('/profile');
      } catch (error) {
        console.error('Callback error:', error);
        navigate('/login?error=callback_failed');
      }
    };

    handleGoogleCallback();
  }, [navigate, searchParams, register]);

  return (
    <div className="min-h-screen flex items-center justify-center" style={{ backgroundColor: '#0a0a0a' }}>
      <div className="text-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-red-600 mx-auto mb-4"></div>
        <p className="text-white text-lg">جاري تسجيل الدخول...</p>
        <p className="text-gray-400 text-sm mt-2">يرجى الانتظار</p>
      </div>
    </div>
  );
};

export default GoogleCallback;
